mapper.select:
SELECT COUNT(*)
FROM board_like
WHERE board_no  = #{boardNo}
  AND member_no = #{memberNo}

mapper.delete:
DELETE FROM board_like
WHERE board_no  = #{boardNo}
  AND member_no = #{memberNo}

mapper.update:
UPDATE board
SET like_count = like_count + 1
WHERE no = #{boardNo}

UPDATE board
SET like_count = like_count - 1
WHERE no = #{boardNo}

